function minStack(operations, values) {
  const stack = [];
  const minS = [];
  const results = [];
  for (let i = 0; i < operations.length; i++) {
    const op = operations[i];
    const args = values[i];
    if (op === 'MinStack') {
      results.push(null);
      continue;
    }
    if (op === 'push') {
      const val = args[0];
      stack.push(val);
      minS.push(minS.length === 0 ? val : Math.min(val, minS[minS.length - 1]));
      results.push(null);
      continue;
    }
    if (op === 'pop') {
      stack.pop();
      minS.pop();
      results.push(null);
      continue;
    }
    if (op === 'top') {
      results.push(stack[stack.length - 1]);
      continue;
    }
    if (op === 'getMin') {
      results.push(minS[minS.length - 1]);
      continue;
    }
  }
  return results;
}
